from typing import List

class Solution:
    def timeClassification(self, timeRange: str) -> List[int]:
        # 去掉多余的空格与引号
        timeRange = timeRange.strip()
        if len(timeRange) >= 2 and timeRange[0] == '"' and timeRange[-1] == '"':
            timeRange = timeRange[1:-1]

        # 拆分起止时间
        start_str, end_str = timeRange.split()
        h1, m1 = map(int, start_str.split(":"))
        h2, m2 = map(int, end_str.split(":"))

        start = h1 * 60 + m1
        end = h2 * 60 + m2

        # 三个档位分钟统计
        ans = [0, 0, 0]
        second_cnt = 0  # 第二档累计分钟数

        for i in range(start, end):
            # 第一档固定优先判断
            if (12 * 60 <= i < 13 * 60 + 30) or (17 * 60 + 30 <= i < 18 * 60):
                ans[0] += 1
            elif second_cnt < 600:
                # 非第一档的前 600 分钟属于第二档
                ans[1] += 1
                second_cnt += 1
            else:
                # 其余分钟归第三档
                ans[2] += 1

        return ans
```

```java
import java.util.*;

public class Solution {
    public int[] timeClassification(String timeRange) {
        // 去除引号与空格
        timeRange = timeRange.trim();
        if (timeRange.length() >= 2 && timeRange.charAt(0) == '"' && timeRange.charAt(timeRange.length() - 1) == '"') {
            timeRange = timeRange.substring(1, timeRange.length() - 1);
        }

        // 拆分时间段
        String[] parts = timeRange.split(" ");
        String[] startArr = parts[0].split(":");
        String[] endArr = parts[1].split(":");

        int start = Integer.parseInt(startArr[0]) * 60 + Integer.parseInt(startArr[1]);
        int end = Integer.parseInt(endArr[0]) * 60 + Integer.parseInt(endArr[1]);

        int[] ans = new int[3];
        int secondCnt = 0;

        for (int i = start; i < end; i++) {
            // 第一档固定优先
            if ((i >= 12 * 60 && i < 13 * 60 + 30) ||
                (i >= 17 * 60 + 30 && i < 18 * 60)) {
                ans[0]++;
            } else if (secondCnt < 600) {
                // 非第一档累计前 600 分钟属于第二档
                ans[1]++;
                secondCnt++;
            } else {
                // 超过后进入第三档
                ans[2]++;
            }
        }

        return ans;
    }
}
