var timeClassification = function(timeRange) {
    // 提取时间部分
    const parts = timeRange.match(/\d+/g).map(Number);
    const start = parts[0] * 60 + parts[1];
    const end = parts[2] * 60 + parts[3];
    // 判断是否在第一档区间
    const isTier1 = (m) => (m >= 720 && m < 810) || (m >= 1050 && m < 1080);
    const result = [0, 0, 0];
    let cumulNonTier1 = 0;

    for (let m = start; m < end; m++) {
        if (isTier1(m)) result[0]++;
        else if (cumulNonTier1 < 600) {
            result[1]++;
            cumulNonTier1++;
        } else result[2]++;
    }
    return result;
};
