// 判断是否为第一档时间
static int _isTier1(int minute) {
    return (minute >= 720 && minute < 810) || (minute >= 1050 && minute < 1080);
}

int* timeClassification(char* timeRange, int* returnSize) {
    // 去除首尾可能的引号
    if (timeRange[0] == '"') timeRange++;
    int len = (int)strlen(timeRange);
    if (len > 0 && timeRange[len - 1] == '"') timeRange[len - 1] = '\0';

    // 解析输入时间
    int h1, m1, h2, m2;
    sscanf(timeRange, "%d:%d %d:%d", &h1, &m1, &h2, &m2);
    int start = h1 * 60 + m1;
    int end = h2 * 60 + m2;

    *returnSize = 3;
    int* result = (int*)calloc(3, sizeof(int));
    int cumulNonTier1 = 0;

    for (int m = start; m < end; m++) {
        if (_isTier1(m)) result[0]++;
        else if (cumulNonTier1 < 600) {
            result[1]++;
            cumulNonTier1++;
        } else result[2]++;
    }
    return result;
}
